def fibonacci(n):
    if n < 0:
        raise ValueError("n must be non-negative")
    if n <= 1:
        return n
    cache = {}
    def _fast_double(k):
        if k in cache:
            return cache[k]
        if k == 0:
            result = (0, 1)
        else:
            a, b = _fast_double(k >> 1)
            c = a * (2 * b - a)
            d = a * a + b * b
            if k & 1:
                result = (d, c + d)
            else:
                result = (c, d)
        cache[k] = result
        return result
    return _fast_double(n)[0]

def fibonacci(n):
    if n < 0:
        raise ValueError("n must be non-negative")
    if n <= 1:
        return n
    a, b = 0, 1
    for bit in range(n.bit_length() - 1, -1, -1):
        c = a * (2 * b - a)
        d = a * a + b * b
        if (n >> bit) & 1:
            a, b = d, c + d
        else:
            a, b = c, d
    return a

